<template>
  <v-app>
    <template v-if="$route.path !== '/'">
      <Navigation />
      <Headerbar @toggle-menu="drawer = !drawer" />
    </template>
    <v-main>
      <v-container fluid class="pa-0" :style="$route.path === '/' ? 'min-height:100vh;' : ''">
        <template v-if="$route.path === '/'">
          <Login/>
        </template>
        <template v-else>
          <router-view />
        </template>
      </v-container>
    </v-main>
  </v-app>
</template>

<script>

import Login from './components/Login.vue';
import Navigation from './components/Navigation.vue';
import Headerbar from './components/Headerbar.vue';
export default {
  name: "App",
  components: {
    Login,
    Navigation,
    Headerbar
  },
  data() {
    return {
      drawer: true
    };
  },
  created() {
    const saved = localStorage.getItem('eloyer-dark-mode');
    if (saved !== null && this.$vuetify) {
      this.$vuetify.theme.dark = saved === 'true';
    }
  },
};
</script>
